parameters.jsCode:
const resp = $input.first().json.content[0].text;
let msgs;
try { msgs = JSON.parse(resp); } catch(e) { const m = resp.match(/\{[\s\S]*\}/); msgs = m ? JSON.parse(m[0]) : { msg_indicado: resp, msg_indicador: '' }; }
const data = $('Webhook - Nova Indicacao Recebida').first().json.body;
return [{ json: { ...msgs, indicador: data.indicador_nome, indicado: data.indicado_nome, telefone: data.indicado_telefone, produto: data.produto_interesse, status: 'NOVO', data_indicacao: new Date().toISOString() } }];
